UPDATE users
SET
    role = #{role},
    updated_at = #{updatedAt}
WHERE id = #{userId}

UPDATE users
SET
    status = #{status},
    updated_at = #{updatedAt}
WHERE id = #{userId}

mapper.select:
SELECT U.ID AS userId, U.NAME AS name, U.NICKNAME AS nickname, U.LEVEL AS level, T.starts_at AS recentSession, T.title AS recentSessionTitle, U.STATUS AS status, U.ROLE AS role FROM USERS U LEFT JOIN ( -- 유저별로(DISTINCT ON) 시작시간 내림차순(DESC) 정렬하여 최신 1건만 추출 SELECT DISTINCT ON (user_id) a.user_id, s.starts_at, s.title FROM SESSION_APPLICATIONS a INNER JOIN SESSIONS s ON a.session_id = s.id WHERE a.status = 'CONFIRMED' AND s.status = 'CLOSED' ORDER BY a.user_id, s.starts_at DESC ) AS T ON U.ID = T.user_id
and ( U.NAME LIKE '%' || #{query} || '%' OR U.NICKNAME LIKE '%' || #{query} || '%' )
and ( U.ROLE in
#{role}
)
ORDER BY U.ID ASC LIMIT #{limit} OFFSET #{offset}
